# ❌ ANTI-PATTERN: Always correcting, ignoring confidence signals
class NaiveRAG:
    def retrieve_and_respond(self, batsman_query):
        retrieved_docs = self.retriever.search(batsman_query)
        response = self.llm.generate(batsman_query, retrieved_docs)
        # Always correct, even for high-confidence cases
        verification_result = self.corrector.verify(response, retrieved_docs)
        return self.llm.correct(response, verification_result)
        # Cost: $0.015/query, latency: 2.8s for ALL queries

# ✅ BEST PRACTICE: Confidence-aware routing with fallback
class AdaptiveRAG:
    def retrieve_and_respond(self, batsman_query):
        retrieved_docs = self.retriever.search(batsman_query)
        retrieval_confidence = self.compute_confidence(
            docs=retrieved_docs,
            query_embedding=self.embed(batsman_query)
        )

        response = self.llm.generate(batsman_query, retrieved_docs)

        if retrieval_confidence > 0.85:
            return response  # Confident path: ~0.8s, $0.004

        elif retrieval_confidence > 0.50:
            verification = self.corrector.verify(response, retrieved_docs)
            if verification['needs_correction']:
                response = self.llm.correct(response, verification)
            return response  # Conservative path: ~1.8s, $0.012

        else:
            # Low confidence: requery with expanded context
            expanded_docs = self.retriever.search(
                batsman_query, 
                top_k=10,  # Increase from 5 to 10
                use_sparse=True  # Add sparse retrieval
            )
            response = self.llm.generate(batsman_query, expanded_docs)
            return self.llm.correct(
                response, 
                self.corrector.verify(response, expanded_docs)
            )  # Fallback path: ~2.2s, $0.014

    def compute_confidence(self, docs, query_embedding):
        # Confidence = 1st-2nd doc similarity margin × retrieval_rank_score
        similarity_margin = docs[0]['score'] - docs[1]['score']
        diversity_penalty = 1.0 - (self.compute_diversity(docs) / 0.5)
        return min(1.0, similarity_margin * 0.7 + diversity_penalty * 0.3)
